import React, { useEffect } from 'react';

import type { TreeParams } from '../Tree.types';
import { useTreeContext } from '../TreeContext';
import type { TreeNodesWrapperProps } from './TreeNodesWrapper.types';

export const TreeNodesWrapper: React.FC<TreeNodesWrapperProps> = ({
	children,
	size,
	multiselect,
	amount,
	expandOnArrow,
	onExpandCallback,
}) => {
	const { changeTreeParams } = useTreeContext();

	useEffect(() => {
		const params: TreeParams = {
			amount: amount,
			size: size,
			multiselect: multiselect,
			expandOnArrow: expandOnArrow,
			onExpandCallback: onExpandCallback,
		};
		changeTreeParams(params); // пишем параметры в контекст ради удобства
	}, [size, multiselect, amount, expandOnArrow, onExpandCallback]);

	return <>{children}</>;
};
